          ? "mt-4 h-0.5 flex-1 mx-2"
          : "ms-4 w-0.5 flex-1 my-2",
        className
      )}
      {...props}
    />
  )
}

// ---------------------------------------------------------------------------
// StepperPanel (content for a step)
// ---------------------------------------------------------------------------

interface StepperPanelProps extends React.ComponentProps<"div"> {
  /**
   * When `true` the panel is kept in the DOM when inactive (hidden with CSS).
   * When `false` (default) inactive panels are unmounted.
   */
  keepMounted?: boolean
}

function StepperPanel({
  className,
  keepMounted = false,
  children,
  ...props
}: StepperPanelProps) {
  const { isActive } = useStepperItemContext()

  if (!keepMounted && !isActive) {
    return null
  }

  return (
    <div
      role="tabpanel"
      hidden={!isActive}
      data-slot="stepper-panel"
      data-state={isActive ? "active" : "inactive"}
      className={cn(
        "text-sm text-foreground",
        !isActive && "hidden",
        className
      )}
      {...props}
    >
      {children}
    </div>
  )
}

export {
  Stepper,
  StepperItem,
  StepperTrigger,
  StepperIndicator,
  StepperTitle,
  StepperDescription,
  StepperSeparator,
  StepperPanel,
  useStepperContext,
  useStepperItemContext,
}

