"use client"

import * as React from "react"
import { CheckIcon } from "lucide-react"

import { cn } from "@/lib/utils"

// ---------------------------------------------------------------------------
// Context
// ---------------------------------------------------------------------------

interface StepperContextValue {
  /** Index of the currently active step (0-based). */
  activeStep: number
  /** Total number of steps rendered inside this Stepper. */
  totalSteps: number
  /** Call to programmatically change the active step. */
  setActiveStep: (step: number) => void
  /** Visual / layout orientation of the stepper. */
  orientation: "horizontal" | "vertical"
}

const StepperContext = React.createContext<StepperContextValue | null>(null)

function useStepperContext(): StepperContextValue {
  const ctx = React.useContext(StepperContext)
  if (!ctx) {
    throw new Error(
      "Stepper sub-components must be rendered inside a <Stepper> component."
    )
  }
  return ctx
}

// ---------------------------------------------------------------------------
// Per-item context (populated by StepperItem)
// ---------------------------------------------------------------------------

interface StepperItemContextValue {
  /** 1-based step number (matches natural user-facing numbering). */
  step: number
  /** Whether this item is the currently active step. */
  isActive: boolean
  /** Whether this item has already been completed (step < activeStep). */
  isCompleted: boolean
  /** Whether interaction with this step's trigger is disabled. */
  disabled: boolean
}

const StepperItemContext = React.createContext<StepperItemContextValue | null>(
  null
)

function useStepperItemContext(): StepperItemContextValue {
  const ctx = React.useContext(StepperItemContext)
  if (!ctx) {
    throw new Error(
      "StepperTrigger / StepperTitle / StepperDescription / StepperPanel must be rendered inside a <StepperItem>."
    )
  }
  return ctx
}

// ---------------------------------------------------------------------------
// Stepper (root container)
// ---------------------------------------------------------------------------

interface StepperProps extends React.ComponentProps<"div"> {
  /** Index of the active step (controlled). */
  activeStep?: number
  /** Callback fired when the user requests a step change. */
  onStepChange?: (step: number) => void
  /** Default active step index when uncontrolled (default: 0). */
  defaultActiveStep?: number
  /** Layout orientation (default: "horizontal"). */
  orientation?: "horizontal" | "vertical"
}

function Stepper({
  activeStep: activeStepProp,
  onStepChange,
  defaultActiveStep = 0,
  orientation = "horizontal",
  className,
  children,
  ...props
}: StepperProps) {
  const [internalStep, setInternalStep] = React.useState(defaultActiveStep)
  const isControlled = activeStepProp !== undefined
  const activeStep = isControlled ? activeStepProp : internalStep

  const handleSetActiveStep = React.useCallback(
    (step: number) => {
      if (!isControlled) {
        setInternalStep(step)
      }
      onStepChange?.(step)
    },
    [isControlled, onStepChange]
  )

  // Count the number of StepperItem children to expose totalSteps.
  const totalSteps = React.useMemo(
    () =>
      React.Children.toArray(children).filter((child) => {
        return (
          React.isValidElement(child) &&
          (child.type === StepperItem ||
            (child as React.ReactElement<{ "data-slot"?: string }>).props[
              "data-slot"
            ] === "stepper-item")
        )
      }).length,
    [children]
  )

  return (
    <StepperContext.Provider
      value={{ activeStep, totalSteps, setActiveStep: handleSetActiveStep, orientation }}
    >
      <div
        data-slot="stepper"
        data-orientation={orientation}
        className={cn(
          "flex",
          orientation === "horizontal"
            ? "flex-row items-start"
            : "flex-col items-stretch",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperContext.Provider>
  )
}

// ---------------------------------------------------------------------------
// StepperItem
// ---------------------------------------------------------------------------

interface StepperItemProps extends React.ComponentProps<"div"> {
  /** 1-based step number. Must be unique within the stepper. */
  step: number
  /** Disable interaction with this step's trigger. */
  disabled?: boolean
}

function StepperItem({
  step,
  disabled = false,
  className,
  children,
  ...props
}: StepperItemProps) {
  const { activeStep, orientation } = useStepperContext()
  const isActive = activeStep === step - 1
  const isCompleted = activeStep > step - 1

  return (
    <StepperItemContext.Provider value={{ step, isActive, isCompleted, disabled }}>
      <div
        data-slot="stepper-item"
        data-state={isActive ? "active" : isCompleted ? "completed" : "pending"}
        data-orientation={orientation}
        className={cn(
          "group/stepper-item flex",
          orientation === "horizontal"
            ? "flex-col items-center"
            : "flex-row items-start",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperItemContext.Provider>
  )
}

// ---------------------------------------------------------------------------
// StepperTrigger
// ---------------------------------------------------------------------------

interface StepperTriggerProps extends React.ComponentProps<"button"> {
  /**
   * When `true` the trigger renders only its children without the
   * default indicator + label layout wrapper.  Useful when you want
   * complete control over the inner markup.
   */
  asChild?: boolean
}

function StepperTrigger({
  className,
  disabled: disabledProp,
  children,
  onClick,
  ...props
}: StepperTriggerProps) {
  const { setActiveStep, orientation } = useStepperContext()
  const { step, isActive, isCompleted, disabled: itemDisabled } = useStepperItemContext()

  const isDisabled = disabledProp ?? itemDisabled

  const handleClick = React.useCallback(
    (e: React.MouseEvent<HTMLButtonElement>) => {
      if (!isDisabled) {
        setActiveStep(step - 1)
      }
      onClick?.(e)
    },
    [isDisabled, setActiveStep, step, onClick]
  )

  return (
    <button
      type="button"
      role="tab"
      aria-selected={isActive}
      aria-current={isActive ? "step" : undefined}
      data-slot="stepper-trigger"
      data-state={isActive ? "active" : isCompleted ? "completed" : "pending"}
      data-orientation={orientation}
      disabled={isDisabled}
      className={cn(
        "inline-flex items-center gap-2 rounded-md text-sm font-medium transition-colors",
        orientation === "vertical" && "w-full",
        "disabled:pointer-events-none disabled:opacity-50",
        "focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2",
        className
      )}
      onClick={handleClick}
      {...props}
    >
      {children}
    </button>
  )
}

// ---------------------------------------------------------------------------
// StepperIndicator
// ---------------------------------------------------------------------------

function StepperIndicator({
  className,
  children,
  ...props
}: React.ComponentProps<"span">) {
  const { step, isActive, isCompleted } = useStepperItemContext()

  return (
    <span
      data-slot="stepper-indicator"
      data-state={isActive ? "active" : isCompleted ? "completed" : "pending"}
      aria-hidden="true"
      className={cn(
        "inline-flex size-8 shrink-0 items-center justify-center rounded-full border-2 text-sm font-semibold transition-colors",
        // pending
        "border-border bg-background text-muted-foreground",
        // active
        "group-data-[state=active]/stepper-item:border-primary group-data-[state=active]/stepper-item:bg-primary group-data-[state=active]/stepper-item:text-primary-foreground",
        // completed
        "group-data-[state=completed]/stepper-item:border-primary group-data-[state=completed]/stepper-item:bg-primary group-data-[state=completed]/stepper-item:text-primary-foreground",
        className
      )}
      {...props}
    >
      {isCompleted && !children ? (
        <CheckIcon className="size-4" aria-hidden="true" />
      ) : (
        children ?? step
      )}
    </span>
  )
}

// ---------------------------------------------------------------------------
// StepperTitle
// ---------------------------------------------------------------------------

function StepperTitle({
  className,
  ...props
}: React.ComponentProps<"span">) {
  return (
    <span
      data-slot="stepper-title"
      className={cn(
        "text-sm font-semibold leading-none text-foreground",
        "group-data-[state=pending]/stepper-item:text-muted-foreground",
        className
      )}
      {...props}
    />
  )
}

// ---------------------------------------------------------------------------
// StepperDescription
// ---------------------------------------------------------------------------

function StepperDescription({
  className,
  ...props
}: React.ComponentProps<"span">) {
  return (
    <span
      data-slot="stepper-description"
      className={cn(
        "text-xs text-muted-foreground",
        className
      )}
      {...props}
    />
  )
}

// ---------------------------------------------------------------------------
// StepperSeparator
// ---------------------------------------------------------------------------

function StepperSeparator({
  className,
  ...props
}: React.ComponentProps<"div">) {
  const { orientation } = useStepperContext()
  const { isCompleted } = useStepperItemContext()

  return (
    <div
      role="none"
      data-slot="stepper-separator"
      data-orientation={orientation}
      data-state={isCompleted ? "completed" : "pending"}
      className={cn(
        "shrink-0 rounded-full bg-border transition-colors",
        "data-[state=completed]:bg-primary",
        orientation === "horizontal"
          ? "mt-4 h-0.5 flex-1 mx-2"
          : "ms-4 w-0.5 flex-1 my-2",
        className
      )}
      {...props}
    />
  )
}

// ---------------------------------------------------------------------------
// StepperPanel (content for a step)
// ---------------------------------------------------------------------------

interface StepperPanelProps extends React.ComponentProps<"div"> {
  /**
   * When `true` the panel is kept in the DOM when inactive (hidden with CSS).
   * When `false` (default) inactive panels are unmounted.
   */
  keepMounted?: boolean
}

function StepperPanel({
  className,
  keepMounted = false,
  children,
  ...props
}: StepperPanelProps) {
  const { isActive } = useStepperItemContext()

  if (!keepMounted && !isActive) {
    return null
  }

  return (
    <div
      role="tabpanel"
      hidden={!isActive}
      data-slot="stepper-panel"
      data-state={isActive ? "active" : "inactive"}
      className={cn(
        "text-sm text-foreground",
        !isActive && "hidden",
        className
      )}
      {...props}
    >
      {children}
    </div>
  )
}

export {
  Stepper,
  StepperItem,
  StepperTrigger,
  StepperIndicator,
  StepperTitle,
  StepperDescription,
  StepperSeparator,
  StepperPanel,
  useStepperContext,
  useStepperItemContext,
}
